import{_ as t,a as r}from"./chunks/Devtools.Deqjth49.js";import{_ as s,c as n,o as a,ah as e}from"./chunks/framework.RCw5T9E9.js";const _=JSON.parse('{"title":"Режимы отображения","description":"","frontmatter":{"title":"Режимы отображения"},"headers":[],"relativePath":"ru/options/display_mode.md","filePath":"ru/options/display_mode.md"}'),g={name:"ru/options/display_mode.md"};function l(p,o,i,d,u,c){return a(),n("div",null,[...o[0]||(o[0]=[e('<h1 id="режимы-отображения-display-mode" tabindex="-1">Режимы отображения (Display Mode) <a class="header-anchor" href="#режимы-отображения-display-mode" aria-label="Permalink to &quot;Режимы отображения (Display Mode)&quot;">​</a></h1><p>В <strong>Options → General → Display Mode</strong> выбирается, <strong>где</strong> живёт интерфейс Vue Inspector относительно страницы. Доступны варианты <strong>Overlay</strong> (оверлей на странице) и <strong>DevTools tab</strong> (вкладка в инструментах разработчика браузера).</p><blockquote><p><strong>Режим DevTools доступен только в установленном расширении</strong> (Chrome / Edge). В <strong>автономном (standalone)</strong> запуске переключатель отключён: инспектор работает как оверлей на странице, отдельной вкладки в DevTools нет.</p></blockquote><p>После смены режима расширение подсказывает <strong>перезагрузить страницу</strong>, чтобы применить выбор.</p><hr><h2 id="overlay-—-оконныи-режим-пилюля-и-размер" tabindex="-1">Overlay — оконный режим, пилюля и размер <a class="header-anchor" href="#overlay-—-оконныи-режим-пилюля-и-размер" aria-label="Permalink to &quot;Overlay — оконный режим, пилюля и размер&quot;">​</a></h2><p><img src="'+t+'" alt="Окно приложения"></p><p>В режиме <strong>Overlay</strong> панель встраивается поверх сайта в собственном «окне» внутри вкладки.</p><p><strong>Пилюля</strong> (компактная кнопка с ручкой перетаскивания и стрелкой‑шевроном) — главная точка управления:</p><ul><li><strong>Шеврон</strong> раскрывает или сворачивает панель с интерфейсом инспектора.</li><li>За <strong>ручку с точками</strong> можно <strong>перетаскивать</strong> блок: при отпускании около края окна он <strong>примагничивается</strong> к верхнему, нижнему, левому или правому краю; если оставить посередине — включается <strong>плавающее окно</strong> с рамкой и тенью.</li></ul><p><strong>Поведение по умолчанию</strong> при первом открытии: пристыковка к <strong>нижнему краю</strong> вкладки. В этом состоянии полоса панели тянется <strong>на всю ширину окна</strong>: сайт остаётся виден сверху, инспектор занимает полоску снизу (высоту можно менять). Это и есть типичный «нижний док» с горизонтальным растяжением.</p><p><strong>Изменение размера:</strong></p><ul><li>В пристыкованном режиме на <strong>внешнем</strong> краю панели есть <strong>зацеп для растягивания</strong> (у нижнего дока это <strong>верхняя</strong> граница полосы): так меняется <strong>высота</strong> нижней и верхней пристыковки или <strong>ширина</strong> левой и правой.</li><li>В <strong>плавающем</strong> режиме доступны <strong>углы и стороны</strong> рамки для произвольного изменения ширины и высоты.</li></ul><p>Размеры, положение дока и координаты плавающего окна <strong>запоминаются</strong> между визитами на сайт (в пределах возможностей браузера и профиля расширения).</p><p>Показ самой пилюли на сайте в оверлее может дополнительно ограничиваться правилами <strong>Auto Run</strong> (чёрный и белый списки сайтов) — см. <a href="/qa-tools/docs/ru/options/auto_run.html">Автозапуск</a>.</p><hr><h2 id="devtools-tab-—-вкладка-в-инструментах-разработчика" tabindex="-1">DevTools tab — вкладка в инструментах разработчика <a class="header-anchor" href="#devtools-tab-—-вкладка-в-инструментах-разработчика" aria-label="Permalink to &quot;DevTools tab — вкладка в инструментах разработчика&quot;">​</a></h2><p><img src="'+r+'" alt="DevTools"></p><blockquote><p><strong>Только расширение.</strong> В этом режиме интерфейс инспектора открывается как <strong>отдельная вкладка</strong> внутри штатных <strong>DevTools</strong> браузера (окно по <strong>F12</strong> или «Просмотреть код»), а не как плавающая панель над страницей.</p></blockquote><p>Удобно, если вы привыкли держать всё рядом с консолью и сетью, или не хотите перекрывать вёрстку сайта оверлеем. Перетаскивание пилюли и докинг к краям страницы <strong>относятся к режиму Overlay</strong>; в DevTools‑вкладке используется раскладка панели инструментов браузера.</p><p>После переключения на <strong>DevTools tab</strong> <strong>перезагрузите страницу</strong> и откройте DevTools — в списке вкладок панели появится <strong>Vue Inspector</strong> (или аналогичное имя панели расширения).</p><p><strong>Обновление страницы (F5):</strong> вкладка с инспектором <strong>заново подключается</strong> к контексту этой же вкладки сайта. Ничего дополнительно «включать» после перезагрузки не требуется.</p><p><strong>В отличие от Overlay:</strong> пока оверлей <strong>свёрнут</strong> (видна только пилюля), часть сценариев на стороне страницы может не получать полноценного канала к развёрнутой панели — тогда для срабатывания тех же <strong>Breakpoint</strong> или <strong>Mock</strong> иногда нужно <strong>сначала развернуть</strong> панель. В режиме <strong>DevTools</strong> вкладка инспектора для браузера уже <strong>активный элемент интерфейса</strong> инструментов разработчика: перехват и подмена по правилам <strong>Network</strong> работают <strong>сразу</strong>, без лишнего шага «открыть панель».</p><p><strong>Network после F5:</strong> список запросов <strong>очищается и заполняется заново</strong> по мере новой загрузки страницы, но сам функционал вкладки <strong>Network</strong> (перехват, точки останова, mock и т.д.) <strong>готов к работе с первого момента</strong> после перезагрузки — не нужно дополнительно кликать по инспектору, чтобы «пробудить» сеть.</p><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/ru/options/auto_run.html">Автозапуск</a> — когда пилюля оверлея показывается автоматически</li><li><a href="/qa-tools/docs/ru/options/customize.html">Персонализация</a> — тема и фон панели</li><li><a href="/qa-tools/docs/ru/extension.html">Расширение браузера</a></li></ul>',27)])])}const v=s(g,[["render",l]]);export{_ as __pageData,v as default};
